module my_alu(
        input [2:0] op,
        input mode,
        input [3:0] A,
        input [3:0] B,
        input [3:0] C,
        output [3:0] X,
        output [3:0] Y,
);

always @* begin
        if (mode) begin
                (* full_case, parallel_case *)
                casez (op)
                        3'b??1: begin
                                X = A & B;
                                Y = A & C;
                        end
                        3'b?1?: begin
                                X = A | B;
                                Y = A | C;
                        end
                        3'b1??: begin
                                X = A ^ B;
                                Y = A ^ C;
                        end
                endcase
        end else begin
                if (op[0])
                        X = A * B;
                else
                        X = 0;
                if (op[1])
                        Y = A * C;
                else
                        Y = 0;
        end
end

endmodule
